public void Add(T item, int maxListCount)
            {
                lock (_list)
                {
                    if (maxListCount > 0)
                    {
                        while (_list.Count >= maxListCount)
                            _list.RemoveAt(0);
                    }
                    _list.Add(item);
                }
            }

private void EnsureSize(IArrayPool<char>? bufferPool, int appendLength)
        {
            char[] newBuffer = BufferUtils.RentBuffer(bufferPool, (_position + appendLength) * 2);

            if (_buffer != null)
            {
                Array.Copy(_buffer, newBuffer, _position);
                BufferUtils.ReturnBuffer(bufferPool, _buffer);
            }

            _buffer = newBuffer;
        }

if (!string.IsNullOrEmpty(_perfFile))
            {
                string normalizedCounter = counter.Replace(':', '_');
