                _table[entry.SiloAddress] = (entry.Copy(), _lastETagCounter++.ToString(CultureInfo.InvariantCulture));
                _tableVersion = new TableVersion(version.Version, NewETag());
                return true;
            }

lock (_lock)
            {
                var entries = _table.Values.ToList();
